use prompty::model::GuardrailResult;
use prompty::model::context::{LoadContext, SaveContext};

#[test]
fn test_guardrail_result_load_json() {
    let json = r####"
{
  "allowed": true,
  "reason": "Content is safe"
}
"####;
    let ctx = LoadContext::default();
    let result = GuardrailResult::from_json(json, &ctx);
    assert!(
        result.is_ok(),
        "Failed to load from JSON: {:?}",
        result.err()
    );
    let instance = result.unwrap();
    assert_eq!(instance.allowed, true);
    assert!(instance.reason.is_some(), "Expected reason to be Some");
    assert_eq!(instance.reason.as_ref().unwrap(), &"Content is safe");
}

